import React, { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/all";
gsap.registerPlugin(ScrollTrigger);

const datas = [
  {
    id: 0,
    title: "1. Requirement Collection",
    desc: "We study your business needs, goals, and ideas to understand how AI can help solve problems and improve your daily operations.",
  },
  {
    id: 1,
    title: "2. AI Solution Planning",
    desc: "Our team plans the right AI model, tools, and features to build a solution that fits your business goals and future growth.",
  },
  {
    id: 2,
    title: "3. Development and Testing",
    desc: "We build the AI solution and test it carefully to make sure it works smoothly, gives accurate results, and runs without issues.",
  },
  {
    id: 3,
    title: "4. Deployment and Support",
    desc: "After launch, we help you run the AI system smoothly and provide support to keep the solution updated and working well..",
  },
];

const DevelopmentProcess = () => {
  const timeLinecontainerRef = useRef(null);

  useEffect(() => {
    const boxes = gsap.utils.toArray(".time-line-box");

    boxes.forEach((box) => {
      ScrollTrigger.create({
        trigger: box,
        start: "top center",
        end: "bottom center",
        onEnter: () => box.classList.add("active"),
        onLeaveBack: () => box.classList.remove("active"),
      });
    });
  }, []);

  return (
    <section className="service-hero-wrapper gap-xl col_flex_column">
      <div className="col_flex_column gap-md">
        <span className="gradient-badge">Development Process</span>
        <h2 className="about-h3 c-text-center md-c-text-start">
          Our AI Development Process
        </h2>
      </div>
      {/*  */}
      <div className="timeline-container" ref={timeLinecontainerRef}>
        <div className="timeline-stick"></div>

        {datas.map((data, index) => (
          <div
            key={data.id}
            className={`time-line-box ${
              index % 2 !== 0 ? "left-box" : "right-box"
            }`}
          >
            <div className="dot"></div>
            <div className="timeline-content item-start">
              <p className="about-p-two fw-600">{data.title}</p>
              <p className="about-p-three">{data.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default DevelopmentProcess;
