// ai-development-company

import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import AIDevelopmentCompanyPage from "@screens/ai-screens/ai-development-company";

const AIDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "AI Development Company Services", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.hire3dDesignerImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const validFaq = data?.allFaqJson?.nodes[0].faqs;
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "AI Development Company delivering custom AI solutions, machine learning models, and automation services to accelerate business growth and innovation.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1688",
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "What company is leading AI development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "OpenAI is widely seen as a leader in AI development today. It builds powerful AI models used for chat, coding, research, and automation. Along with strong innovation and partnerships with Microsoft, the company continues to push AI technology forward.",
            },
          },
          {
            "@type": "Question",
            name: "Who are the top 5 AI companies?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Some of the top AI companies include OpenAI, Google, Microsoft, Amazon, and IBM. These companies invest heavily in AI research and build tools for automation, cloud services, data analysis, and smart applications used by businesses around the world.",
            },
          },
          {
            "@type": "Question",
            name: "What is an AI development company?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "An AI development company creates software and systems that use artificial intelligence to solve problems. These companies build tools like chatbots, automation platforms, data analysis systems, and smart apps that help businesses work faster, improve decisions, and reduce manual work.",
            },
          },
        ],
      },
    ],
  };
  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <AIDevelopmentCompanyPage db={db} faq={validFaq} />
      </main>
    </Layout_v2>
  );
};

export default AIDevelopmentCompany;
export const queryData = graphql`
  query MyQuery {
    hire3dDesignerImg: file(
      relativePath: { eq: "ai-development-company.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "ai-development-company" } }) {
      nodes {
        metaTitle
        title
        slug
        description
      }
    }
    allFaqJson(filter: { slug: { eq: "ai-development-company" } }) {
      nodes {
        slug
        faqs {
          question
          answer
          status
        }
      }
    }
  }
`;
